  sum(Orders.RndBaseDemand * Catalog.SellPrice) when (Catalog.ItemRank == 6 ) as item6 {color: #0637D8}
  sum(Orders.RndBaseDemand * Catalog.SellPrice) when (Catalog.ItemRank == 7 ) as item7 {color: #910FCE}
  sum(Orders.RndBaseDemand * Catalog.SellPrice) when (Catalog.ItemRank == 8 ) as item8 {color: #6D2504}
